var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SPRIT_FLOOR_GIRL_HOSPITAL","text":{"KOREA":"더 주세요.","JPN":"もっとちょうだい。","ENG":"More please.","TWN":"請再給我一碗。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_03"},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"운이 좋았네. 한겨울에 딸기를 팔다니 말이야.","JPN":"運がよかったわね。真冬にイチゴを売ってるなんて。","ENG":"We were lucky. Finding someone who sells strawberries in the middle of winter.","TWN":"今天運氣很不錯呢。冬天還能遇見賣草莓的。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_SHAKING_COCK"},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"엄마가 해준 스무디가 그렇게 맛있어?","JPN":"お母さんのスムージー、そんなに美味しい？","ENG":"Do you like the smoothie I made you that much?","TWN":"媽媽做的冰沙有那麼好吃嗎？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SPRIT_FLOOR_GIRL_HOSPITAL","text":{"KOREA":"응.","JPN":"うん。","ENG":"Uh-huh.","TWN":"嗯。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SPRIT_FLOOR_GIRL_HOSPITAL","text":{"KOREA":"얼음 좋아요.","JPN":"氷がいい。","ENG":"I love ice.","TWN":"我喜歡冰塊。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"딸기는 어때? 달콤하지?","JPN":"イチゴはどう？　甘いでしょう？","ENG":"How about the strawberries? Aren't they sweet?","TWN":"草莓味道怎麼樣？是不是很甜？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SPRIT_FLOOR_GIRL_HOSPITAL","text":{"KOREA":"음… 으음…","JPN":"うん……うーん……","ENG":"Mm... Mmmmm...","TWN":"唔……嗯……"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SPRIT_FLOOR_GIRL_HOSPITAL","text":{"KOREA":"잘 모르겠어요.","JPN":"よくわからない。","ENG":"I'm not sure.","TWN":"我不知道。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SPRIT_FLOOR_GIRL_HOSPITAL","text":{"KOREA":"차가운 거 좋아요. 얼음 더 넣어주세요.","JPN":"冷たいのがいい。氷をもっとちょうだい。","ENG":"I like cold things. More ice please.","TWN":"我喜歡涼涼的東西。請多給我放些冰塊。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"…그래.","JPN":"……わかったわ。","ENG":"...Of course.","TWN":"……好。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"이따 진찰받으러 가야 하니까, 이번이 마지막 잔이다?","JPN":"もうすぐ診察だから、あと一杯だけよ？","ENG":"You have to go in for a checkup later, so this is the last one, okay?","TWN":"不過待會兒還得去看醫生，這是最後一碗了喔？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SPRIT_FLOOR_GIRL_HOSPITAL","text":{"KOREA":"네-","JPN":"はーい","ENG":"Okay–","TWN":"嗯——"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"…스펜서 씨.","JPN":"……スペンサーさん。","ENG":"...Ms. Spencer?","TWN":"……史賓瑟。"},"stage":{"bg":"white","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"스펜서 씨!","JPN":"スペンサーさん！","ENG":"Ms. Spencer!","TWN":"史賓瑟！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L21_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"괜찮으세요?","JPN":"大丈夫なんですか？","ENG":"Are you okay?","TWN":"你還好嗎？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"내가 집에는 찾아오지 말라고 했을 텐데?","JPN":"家には来るなって言わなかった？","ENG":"I thought I told you not to come to my place.","TWN":"我告訴過你，不要來我家吧？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"저희 만나기로 한 시간이 벌써 두 시간 지났어요. 연락도 안 받아서 걱정했다고요.","JPN":"待ち合わせの時間から2時間も過ぎているんですよ。連絡も取れないので心配したんです。","ENG":"It's been two hours since we were supposed to meet. I got worried because I couldn't reach you.","TWN":"距離約定見面的時間已經過去了整整兩個小時。期間也聯繫不到你，我很擔心。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASSIST_FLOOR_NPC_CULKIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"날 걱정해?","JPN":"心配？　私を？","ENG":"You were worried about me?","TWN":"你擔心我？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"그야 당연하죠. 당신이 저에게 얼마나 큰 고객인데.","JPN":"当然です。あなたは僕にとって大口の顧客なんですよ。","ENG":"Of course. You're an important client of mine.","TWN":"那是當然的。你是我非常重要的大客戶啊。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASSIST_FLOOR_NPC_CULKIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"바닥에 주사기가 굴러다니는 걸 보니, 또 집에서 이터니움 정제액을 쓰셨군요.","JPN":"その床に転がっている注射器、また自宅でエタニウム精製水を使われたんですか。","ENG":"Seeing the needles rolling around, I see that you've been using purified Eternium liquid again.","TWN":"你又在家裡用了永恆之金淨化液了？我看到地板上滾動的注射器了。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ASSIST_FLOOR_NPC_CULKIN","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"맞아. 방금 전에도 약기운 때문에 네 얼굴이 침식체로 보여서 찌를 뻔했지 뭐야?","JPN":"そう。薬のせいであなたが侵食体に見えて、あやうく刺すところだった。","ENG":"Yeah. I even almost stabbed you in the face because you looked like a C.O. from the drug just now.","TWN":"沒錯。因為藥效的關係，剛才我把你看成了侵蝕體，還差點紮到你是嗎？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"그런 것치곤 절 거들떠도 안 보고, 이 스무디만 계속 만들던데요.","JPN":"それにしてはこっちのことなんか気にせず、スムージーばかり作っていましたけど。","ENG":"You weren't even looking at me, and just kept making this smoothie.","TWN":"沒，你甚至沒注意到我，一直在做冰沙。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_03"},{"id":"L33_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"다 마셔도 돼. 어차피 먹을 사람도 없으니까.","JPN":"全部飲んでもいい。どうせ誰も飲まないから。","ENG":"You can have it all. There's no one to drink it anyway.","TWN":"嗯，反正也沒人吃，你可以全部吃掉。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"하하… 여기 있는 걸 다 먹긴 힘들 것 같고, 한 잔만 마실게요.","JPN":"はは……こんなにたくさんは……飲めそうにありませんが、一杯だけいただきます。","ENG":"Haha... I don't think I'll be able to finish all of it. I'll just have a glass.","TWN":"哈，哈……我可吃不下全部，就只吃一碗好了。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"음, 맛있는 딸기네요. 요즘 딸기가 제철이긴 하죠.","JPN":"うむ、イチゴが美味しいですね。そういえばちょうどイチゴの旬ですもんね。","ENG":"Mmm, these strawberries are good. They're in season these days, no?","TWN":"唔，這些草莓很好吃。這幾天正巧是草莓的季節。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"솜씨가 좋으신데요? 레시피 같은 게 따로 있는 건가요?","JPN":"作るのお上手じゃないですか、レシピでもあるんですか？","ENG":"You're good at this. Do you have a secret recipe?","TWN":"你的手藝不錯啊？有食譜之類的嗎？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"잡담은 됐으니 용건이나 말해.","JPN":"余計なお喋りは結構。本題を言いなさい。","ENG":"Enough chit-chat. Get to the chase.","TWN":"閒聊到此為止，我們來談談生意吧。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"저번엔 부탁하신 <color=#ffd34c>조사</color>에 진척이 좀 있었어요.","JPN":"以前頼まれた<color=#ffd34c>調査</color>に進捗があったことについてですが。","ENG":"We made some progress on the <color=#ffd34c>investigation</color> you requested last time.","TWN":"那麼，你上次說的<color=#ffd34c>調查</color>，已經取得了一些進展。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASSIST_FLOOR_NPC_CULKIN","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"3개월전, 최소 둘 이상의 탐사대가 시라사키 측의 허가없이 승강기를 이용했단 정보를 얻었습니다.","JPN":"3カ月前、少なくとも2つ以上の探査部隊がシラサキから許可を得ることなく昇降機を使用したとの情報を入手しました。","ENG":"We obtained information that at least two exploration teams used the elevator without Sirasaki's permission three months ago.","TWN":"三個月前，我們收到消息稱，至少有兩個勘查隊未經白崎許可使用了升降機。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASSIST_FLOOR_NPC_CULKIN","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그게 내가 부탁한 거랑 무슨 상관이지?","JPN":"それは私がお願いした内容と関係ある？","ENG":"What's that got to do with what I asked?","TWN":"這和我的委託有什麼關係？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASSIST_FLOOR_NPC_CULKIN","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"그 탐사대 중에 에드윈 박사로 추정되는 인물이 있었다고 하더군요.","JPN":"その探査部隊にはエッドウィン博士と思われる人物もいたとのことです。","ENG":"It was reported that among those exploration teams, there was an individual suspected to be Dr. Edwin.","TWN":"據說，勘查隊中有一人疑似是艾德溫博士。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASSIST_FLOOR_NPC_CULKIN","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASSIST_FLOOR_NPC_CULKIN","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"3개월 전이라…","JPN":"3カ月前、か……","ENG":"Three months ago…","TWN":"那是3個月前的事了……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASSIST_FLOOR_NPC_CULKIN","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"정보 신선도가 너무 떨어져. 그 추정이란 표현도 마음에 안 들고.","JPN":"情報があまりにも古すぎる。それに「思われる」なんて表現も気に入らない。","ENG":"That information is way too stale. And I don't like the sound of \\"suspected to be.\\"","TWN":"資訊太落後了。我不喜歡疑似這個詞。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ASSIST_FLOOR_NPC_CULKIN","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"수년 전 흔적도 없이 증발한 기밀 프로젝트 연구원을 찾는 일이잖아요. 산책하다 잃어버린 강아지 찾는 거랑 차원이 다르다고요.","JPN":"もう何年も前に、跡形もなく消えてしまった機密プロジェクトの研究員を探そうとしているんですから、散歩中に消えてしまった犬を探すのとはわけが違います。","ENG":"This is about finding a researcher who was working on top secret projects until he disappeared into thin air. This is on a completely different scale than a simple search and rescue.","TWN":"這件事不是關係到多年前神秘失蹤、人間蒸發的機密項目研究員嘛？可不像尋找散步時走失的小狗那麼簡單。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASSIST_FLOOR_NPC_CULKIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그래서, 그걸 뒷받침하는 증거는?","JPN":"それで、裏付けはあるの？","ENG":"All right, fine. So is there any proof?","TWN":"那麼，有什麼證據支持呢？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"이건 시라사키 내부에서 관리하는 승강기 운용 기록입니다.","JPN":"これは昇降機の運用が記録されたシラサキの内部資料です。","ENG":"This is the elevator operation log managed internally by Sirasaki.","TWN":"這是白崎內部保存的升降機運行記錄。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"3번 승강기가 움직였다고…? 그것도 3개월 전에?","JPN":"3番昇降機が稼働している……？　しかも3カ月前に？","ENG":"Elevator 3 moved...? And three months ago at that?","TWN":"3號電梯運行過……？也是3個月前的事？"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"진작에 폐기된 줄 알았는데, 시라사키가 그걸 아직도 운용하고 있었나?","JPN":"とっくに廃棄されたと思っていた。シラサキがまだあの昇降機を運用していたなんて。","ENG":"I thought it had been decommissioned a long time ago. Sirasaki's still operating it?","TWN":"我以為它早就被廢棄了，但是白崎還在操作它嗎？"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"아뇨, 3년 전 캐번디시 탐사대 실종 건 이후로 승강기는 고장 난 채 방치되고 있었습니다.","JPN":"いいえ、3年前のキャベンディッシュ探査部隊失踪事件以来、昇降機は故障したままずっと放置されていました。","ENG":"No, the elevator had been abandoned since the disappearance of the Cavendish expedition three years ago.","TWN":"不，自從三年前卡文迪許勘查隊失蹤以來，就從未啟用過。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"기록에 따르면, 허가 받지 않은 탐사대가 승강기를 수리해서 이용했다고 하더군요.","JPN":"記録によれば、許可していない探査部隊が昇降機を無断で修理し、使ったとのことです。","ENG":"According to the records, an unauthorized expedition tried to repair and use the elevator.","TWN":"根據記錄，有一支未經許可的勘查隊修理並使用了升降機。"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"일개 탐사대가 승강기를 직접 고쳐? 왜 그런 짓까지 하는 거지?","JPN":"一介の探査部隊が昇降機を自分たちで直したというの？　何でそんなことを？","ENG":"An expedition team fixing the elevator on their own? Why go so far?","TWN":"一支勘查隊自己修好了升降機？為什麼還要做這樣的事？"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"대균열 5층까지 내려가는 승강기는 3번 승강기 하나뿐이니까요.","JPN":"大亀裂の5階まで降りられるのは3番昇降機しかありませんからね。","ENG":"Because only elevator 3 goes down to the 5th floor of the Grand Dimension Crevice.","TWN":"通往大峽谷地下五層的升降梯，只有3號機這一部。"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"생환자는?","JPN":"生還者は？","ENG":"Any survivors?","TWN":"誰還活著？"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"한 명도 없었어요.","JPN":"一人もいません。","ENG":"Not a single one.","TWN":"一個也沒回來。"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"리프터의 실종 처리는 닷새가 데드라인이니, 이미 죽었겠죠.","JPN":"リフターの失踪は5日がタイムリミットと言われていますから、もう死亡したとみていいでしょう。","ENG":"The deadline for reporting missing lifters is five days, so they're probably already dead.","TWN":"打撈人失蹤處理的最後期限是五天，所以大概是已經死了。"},"stage":{"bg":"LIFT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"우리 말고 또 누가 그 사건을 알고 있지?","JPN":"私たち以外で、その事件を知っている者はいる？","ENG":"Who else knows about this incident?","TWN":"除了我們之外，還有誰知道這件事？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"그게 말이죠.","JPN":"それなんですが。","ENG":"That's the thing.","TWN":"那個嘛。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASSIST_FLOOR_NPC_CULKIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"스펜서 씨가 2층 탐사를 떠났을 때, 5층에서 조난 신호가 접수됐다고 합니다.","JPN":"スペンサーさんが2階の探査に出ていた日、5階からは救難信号が発せられていたそうです。","ENG":"We heard that when you were down on the 2nd floor, someone sent a distress signal from the 5th floor.","TWN":"聽說，史賓瑟你離開地下二層時，收到了從地下五層發來的遇難訊號。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASSIST_FLOOR_NPC_CULKIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그 5층에서 조난된 인간들은 3번 승강기가 멀쩡하단 걸 알고 이용했다는 거네.","JPN":"5階で遭難していた連中は3番昇降機が修理されていることに気づいて使ったというわけか。","ENG":"So those guys stranded on the 5th floor knew about elevator 3 working.","TWN":"看來那些在地下5層遇難的人，使用的就是3號機。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"맞아요. 3번 승강기가 고쳐진 뒤로 이미 몇 번씩이나 사용되고 있었습니다. 우리가 몰랐을 뿐이죠.","JPN":"そうなんです。3番昇降機は修理されたあと何度も使われていたんです。私たちの気づかないところで。","ENG":"Exactly. Elevator 3 was being used multiple times since it got repaired. We just didn't know.","TWN":"沒錯。自從3號機修好以來，它已經被使用過幾次。我們只是不知道而已。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASSIST_FLOOR_NPC_CULKIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"그리고… 그 조난자들에게 의뢰를 맡긴 의뢰인이 스펜서 씨도 만나고 싶어 했어요.","JPN":"それと……その遭難者たちに依頼を出した依頼主はスペンサーさんとも会いたがっていました。","ENG":"Also... the client who hired the stranded team wants to meet you, Ms. Spencer.","TWN":"另外……那些遇難者的委託人想要見史賓瑟你一面。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"전 당연히 말도 안 되는 제안이라 생각해서 거절했고요.","JPN":"もちろん、ありえない提案だったので、私の方から断っておいたんですが。","ENG":"I thought that was obviously a bad idea, so I refused.","TWN":"當然，我認為這是一個荒謬的提議，所以我拒絕了。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_SHAKING_COCK"},{"id":"L29_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"…연락해. 그리고 내가 직접 만나보고 싶다고 전해.","JPN":"……その人に連絡して。直接会ってみたいと伝えて。","ENG":"...Contact them. Tell them that I want to meet in person.","TWN":"……聯繫他吧。告訴他我想親自見見他。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"푸웁-!! 네에?!","JPN":"ブフオッ！　はいぃっ！？","ENG":"Pfft!! What?!","TWN":"噗——！！什麼？！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASSIST_FLOOR_NPC_CULKIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"아시잖아요! 5층까지 갔다가 살아 돌아온 사람은…!","JPN":"何をおっしゃっているんですか！　5階に行ったきり戻ってこられた人間は……！","ENG":"You know as well as I do! No one's ever returned from the 5th floor–!","TWN":"你知道的吧！從地下5層活著回來的人……！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASSIST_FLOOR_NPC_CULKIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"…지금껏 한 명도 없었지.","JPN":"……今までは一人もいなかったね。","ENG":"…No one's returned so far.","TWN":"……到目前為止一個沒有。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"그걸 알면 왜 그러는 거죠?","JPN":"それを知っていて何をおっしゃってるんですか。","ENG":"Then why are you still willing to go?","TWN":"你既然知道，為什麼還要這麼做？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASSIST_FLOOR_NPC_CULKIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"궁금하잖아.","JPN":"でも気にならない？","ENG":"Because I'm curious.","TWN":"我很好奇。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"죽을 짓이란 걸 뻔히 알면서도, 사고회로 멀쩡한 인간들을 사지로 기어가게 만든 제안이 대체 뭔지 나도 듣고 싶거든.","JPN":"精神に異常をきたしたわけでもない者たちが、命をドブに捨てる行為だとわかっていながらも乗らざるを得ない提案っていったいどんなものなのか。","ENG":"I want to hear what kind of proposal they made that convinced those poor saps to willingly walk into the jaws of death.","TWN":"而且我還想聽聽，是什麼提案會讓這些人明知是去找死，卻還要冒險。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};